-- Migration: expense_archive_authority (EXP-018)
-- 1) Column-aware soft-delete guard: setting deleted_at on an expense (the real
--    delete-equivalent) requires admin, matching the intent of the dead expenses_delete
--    policy. RLS WITH CHECK can't see OLD, so enforce the NULL->non-NULL transition in a
--    BEFORE UPDATE trigger. Reversal/voiding flows through it because the RPC runs as a
--    SECURITY DEFINER whose session user is admin-checked before the UPDATE.

CREATE OR REPLACE FUNCTION public.enforce_expense_archive_authority()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
BEGIN
  -- Only police the transition into archived/soft-deleted state.
  IF NEW.deleted_at IS NOT NULL AND OLD.deleted_at IS NULL THEN
    IF NOT (has_role('admin') OR is_platform_admin()) THEN
      RAISE EXCEPTION 'Only an admin can archive (delete) an expense';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enforce_expense_archive_authority ON public.expenses;
CREATE TRIGGER trg_enforce_expense_archive_authority
  BEFORE UPDATE ON public.expenses
  FOR EACH ROW
  EXECUTE FUNCTION public.enforce_expense_archive_authority();

-- 2) Canonical archival RPC: the single soft-delete path. Mirrors
--    record_expense_disbursement (tenant guard, admin authz inside the definer,
--    FOR UPDATE lock, idempotent guard) and folds in the EXP-006 reversal logic so
--    bulk and single-row delete can never again orphan the GL/VAT.

CREATE OR REPLACE FUNCTION public.archive_expense(p_expense_id uuid, p_reason text DEFAULT NULL::text)
RETURNS public.expenses
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
DECLARE
  v_tenant uuid := get_current_tenant_id();
  v_exp    public.expenses;
  v_txn    record;
BEGIN
  IF v_tenant IS NULL THEN
    RAISE EXCEPTION 'No tenant context';
  END IF;

  -- Authorization (RLS bypassed under SECURITY DEFINER): admin is the canonical
  -- authority for removing a financial record (converges UI + RLS intent, EXP-018).
  IF NOT (has_role('admin') OR is_platform_admin()) THEN
    RAISE EXCEPTION 'Only an admin can archive (delete) an expense';
  END IF;

  -- Lock the expense; tenant-scoped, not already archived (idempotent).
  SELECT * INTO v_exp FROM public.expenses
   WHERE id = p_expense_id AND tenant_id = v_tenant AND deleted_at IS NULL
   FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Expense not found or already archived';
  END IF;

  -- If money posted to the ledger, reverse every linked transaction with a
  -- compensating entry (append-only ledger) and retire its VAT rows so reports
  -- stop counting deleted spend (EXP-006).
  IF v_exp.status IN ('approved', 'paid') THEN
    FOR v_txn IN
      SELECT id FROM public.financial_transactions
       WHERE reference_type = 'expense' AND reference_id = p_expense_id
         AND deleted_at IS NULL
    LOOP
      PERFORM public.reverse_financial_transaction(
        v_txn.id, COALESCE(p_reason, 'Expense archived'));
    END LOOP;

    UPDATE public.vat_records
       SET deleted_at = now()
     WHERE record_id = p_expense_id
       AND record_type IN ('purchase', 'expense')
       AND deleted_at IS NULL;
  END IF;

  -- Cascade attachment soft-delete.
  UPDATE public.expense_attachments
     SET deleted_at = now()
   WHERE expense_id = p_expense_id AND deleted_at IS NULL;

  -- Archive the expense (audit trigger stamps updated_by; the authority trigger
  -- passes because this definer already admin-checked above).
  UPDATE public.expenses
     SET deleted_at = now(), status = 'voided'
   WHERE id = p_expense_id
   RETURNING * INTO v_exp;

  RETURN v_exp;
END;
$$;

REVOKE ALL ON FUNCTION public.archive_expense(uuid, text) FROM public;
GRANT EXECUTE ON FUNCTION public.archive_expense(uuid, text) TO authenticated;

-- EXP-063: server-side enforcement of bulk_import feature + max_expenses_per_month quota on expense bulk import.
-- SECURITY DEFINER so it can read tenant_subscriptions/plan_features regardless of caller RLS; authorize explicitly inside.
-- Mirrors the client resolution in featureGateService.ts: explicit plan_features row wins; else hierarchy fallback for
-- bulk_import (requires 'professional'); else NULL = unlimited for max_expenses_per_month. Counts current calendar-month
-- non-deleted expenses for the caller's tenant.

CREATE OR REPLACE FUNCTION public.assert_expense_import_allowed(p_row_count integer)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_tenant_id   uuid;
  v_plan_code   text;
  v_plan_id     uuid;
  v_plan_rank   integer;
  v_bulk_row    record;       -- plan_features row for bulk_import (may be missing)
  v_bulk_ok     boolean;
  v_limit       integer;      -- max_expenses_per_month limit_value (NULL = unlimited)
  v_limit_found boolean := false;
  v_current     integer;
  v_month_start timestamptz;
BEGIN
  -- Authorize: only accounts-capable staff may bulk-import expenses (same gate as expenses_insert RLS).
  IF NOT has_role('accounts') THEN
    RAISE EXCEPTION 'Not authorized to import expenses'
      USING ERRCODE = '42501';
  END IF;

  IF p_row_count IS NULL OR p_row_count < 0 THEN
    RAISE EXCEPTION 'Invalid import row count'
      USING ERRCODE = '22023';
  END IF;

  v_tenant_id := get_current_tenant_id();
  IF v_tenant_id IS NULL THEN
    -- Platform admin / no-tenant context: nothing to meter, allow.
    RETURN;
  END IF;

  -- Resolve active plan code (default 'starter' when no active subscription), mirroring loadPlanCache().
  SELECT ts.plan_id, sp.code
    INTO v_plan_id, v_plan_code
  FROM tenant_subscriptions ts
  JOIN subscription_plans sp ON sp.id = ts.plan_id
  WHERE ts.tenant_id = v_tenant_id
    AND ts.status = 'active'
    AND ts.deleted_at IS NULL
  ORDER BY ts.created_at DESC
  LIMIT 1;

  v_plan_code := COALESCE(v_plan_code, 'starter');
  v_plan_rank := CASE v_plan_code
                   WHEN 'starter' THEN 1
                   WHEN 'professional' THEN 2
                   WHEN 'enterprise' THEN 3
                   ELSE 0
                 END;

  -- ---- bulk_import feature gate ----
  IF v_plan_id IS NOT NULL THEN
    SELECT * INTO v_bulk_row
    FROM plan_features
    WHERE plan_id = v_plan_id
      AND feature_key = 'bulk_import'
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF FOUND THEN
    v_bulk_ok := COALESCE(v_bulk_row.is_enabled, false);
  ELSE
    -- Hierarchy fallback: bulk_import requires 'professional' (rank 2).
    v_bulk_ok := (v_plan_rank >= 2);
  END IF;

  IF NOT v_bulk_ok THEN
    RAISE EXCEPTION 'Bulk import requires the Professional plan or higher. Please upgrade to import expenses.'
      USING ERRCODE = 'P0001', HINT = 'feature:bulk_import';
  END IF;

  -- ---- max_expenses_per_month quota ----
  IF v_plan_id IS NOT NULL THEN
    SELECT limit_value INTO v_limit
    FROM plan_features
    WHERE plan_id = v_plan_id
      AND feature_key = 'max_expenses_per_month'
      AND deleted_at IS NULL
    LIMIT 1;
    v_limit_found := FOUND;
  END IF;

  -- No explicit limit row => unlimited (matches client: limit = null).
  IF NOT v_limit_found OR v_limit IS NULL THEN
    RETURN;
  END IF;

  v_month_start := date_trunc('month', now());

  SELECT count(*) INTO v_current
  FROM expenses
  WHERE tenant_id = v_tenant_id
    AND deleted_at IS NULL
    AND created_at >= v_month_start;

  IF (v_current + p_row_count) > v_limit THEN
    RAISE EXCEPTION 'This import of % expense(s) would exceed your plan limit of % per month (% already used this month). Please upgrade or reduce the file.',
      p_row_count, v_limit, v_current
      USING ERRCODE = 'P0001', HINT = 'limit:max_expenses_per_month';
  END IF;
END;
$$;

REVOKE ALL ON FUNCTION public.assert_expense_import_allowed(integer) FROM public;
GRANT EXECUTE ON FUNCTION public.assert_expense_import_allowed(integer) TO authenticated;

COMMENT ON FUNCTION public.assert_expense_import_allowed(integer) IS
  'EXP-063: server-side gate for expense bulk import. Authorizes via has_role(accounts); enforces bulk_import feature + max_expenses_per_month quota for the caller tenant; raises on denial.';

-- Migration: expenses_audit_actor_stamping
-- Stamps created_by/updated_by on every expenses write so no path (import, form, RPC) leaves attribution NULL.
CREATE OR REPLACE FUNCTION public.set_expenses_audit_actor()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    NEW.created_by := COALESCE(NEW.created_by, auth.uid());
  ELSIF TG_OP = 'UPDATE' THEN
    -- Preserve prior editor when there is no auth context (system/bypass jobs).
    NEW.updated_by := COALESCE(auth.uid(), NEW.updated_by);
  END IF;
  RETURN NEW;
END;
$function$;

DROP TRIGGER IF EXISTS set_expenses_audit_actor ON public.expenses;
CREATE TRIGGER set_expenses_audit_actor
  BEFORE INSERT OR UPDATE ON public.expenses
  FOR EACH ROW EXECUTE FUNCTION public.set_expenses_audit_actor();

-- No data backfill: historical rows with created_by IS NULL are left unchanged
-- (no reliable actor to attribute retroactively). The existing
-- set_expenses_tenant_and_audit trigger is intentionally left in place.
